def histogram(test):
    """Given a string representing a space-separated string of lowercase letters, this function returns a list of 
    letters that have the lowest frequency along with their corresponding counts. If multiple letters share the 
    lowest frequency, only the first one encountered is returned.

    Example usage:
    - histogram('a b c') returns {'a': 1}
    - histogram('a b b a') returns {'b': 1}
    - histogram('a b c a b') returns {'c': 1}
    - histogram('b b b b a') returns {'a': 1}
    - histogram('') returns {}

    Returns:
        dict: Dictionary with letters as keys and their counts as values for the least frequent letters.
    """

    from collections import Counter

    # Split the input string into letters
    letters = test.split()

    if not letters:
        return {}

    # Count the occurrences of each letter
    letter_count = Counter(letters)

    # Find the minimum count
    min_count = min(letter_count.values())

    # Return the first letter with the minimum count
    for letter, count in letter_count.items():
        if count == min_count:
            return {letter: count}
